// (이슈1) 매트릭스 fetch 단일 진입점 — 중복 fetch 방지.
//  · 이미 mxState[kind].data가 있으면(초기 배지 로드·개요·뷰 진입 등에서 받아둠) 그걸 재사용.
//  · 진행 중인 요청이 있으면 그 promise를 공유(동시 호출이 겹쳐도 fetch는 1회).
//  · force=true면 캐시·in-flight를 무시하고 새로 받는다(새로고침 버튼).
// loadMatrix·loadOverview·initNavCounts가 모두 이 함수를 통해 같은 응답을 공유한다.
function fetchMatrix(kind, force) {
  const st = mxState[kind];
  if (!force && st.data) return Promise.resolve(st.data);
  if (!force && st.inflight) return st.inflight;
  const p = api('/matrix?kind=' + encodeURIComponent(kind))
    .then((m) => { st.data = m; st.inflight = null; return m; })
    .catch((e) => { st.inflight = null; throw e; });
  st.inflight = p;
  return p;
}

